INSERT INTO forum_topics (title, content, author_name, category, views, likes, goal_id, pinned) VALUES
('Как регионы могут ускорить цифровизацию госуслуг?', 'Предлагаю обсудить лучшие практики цифровой трансформации региональных органов власти. В Татарстане успешно внедрили систему МФЦ нового поколения — какие ещё примеры есть?', 'Александр Петров', 'Цифровизация', 1240, 87, 5, TRUE),
('Инструменты снижения уровня бедности: региональный опыт', 'Хотел бы обменяться опытом реализации социальных программ. В нашем регионе запустили адресную помощь через цифровой профиль гражданина — снизили бедность на 2% за год.', 'Мария Сидорова', 'Экономика', 980, 64, 4, FALSE),
('Телемедицина для сельских районов: барьеры и решения', 'Опыт ЯНАО показывает: телемедицина работает даже в Арктике. Главные барьеры — интернет и обучение персонала. Как вы решаете эти проблемы в своих регионах?', 'Дмитрий Козлов', 'Здравоохранение', 756, 52, 1, FALSE),
('Зелёные технологии в ЖКХ: где взять финансирование?', 'Наш город хочет перейти на LED-освещение и установить солнечные панели на муниципальных зданиях. Проблема — нет средств. Есть ли федеральные программы поддержки?', 'Елена Новикова', 'Экология', 543, 38, 6, FALSE),
('Привлечение молодёжи к STEM: что работает?', 'Делюсь опытом: в нашей школе открыли кружок робототехники и участие в олимпиадах выросло в 5 раз. Какие форматы привлекают школьников к науке и технологиям?', 'Игорь Захаров', 'Образование', 891, 73, 2, FALSE),
('Государственно-частное партнёрство в инфраструктуре', 'ГЧП — недооценённый инструмент. В нашем регионе через ГЧП построили 3 школы и 2 больницы без нагрузки на бюджет. Готов поделиться методикой.', 'Анна Фёдорова', 'Инфраструктура', 672, 59, 3, TRUE);
INSERT INTO forum_replies (topic_id, author_name, content, likes) VALUES
(1, 'Виктор Смирнов', 'В Москве используем модель API-first: все госуслуги имеют открытые API, что позволяет интегрировать их в любые приложения. Это дало взрывной рост охвата.', 34),
(1, 'Ольга Белова', 'Ключевой фактор — обучение чиновников. Без цифровой грамотности сотрудников никакие технологии не помогут. Вложили 15% бюджета в обучение.', 28),
(2, 'Сергей Морозов', 'Адресная помощь через цифровой профиль — это прорыв. Интересно, как вы боретесь с ложными заявками? У нас это основная проблема.', 19),
(3, 'Наталья Орлова', 'Мы решили проблему интернета через спутниковую связь — в труднодоступных районах разница колоссальная. Стоимость оборудования окупается за 8 месяцев.', 41),
(5, 'Павел Кириллов', 'Работающий формат — школьные хакатоны вместе с IT-компаниями. Дети видят реальные задачи и реальных профессионалов. После первого хакатона 40% участников выбрали STEM.', 55);